/* Suggested markup: <div class="uiwiki-index-card-route-swap" tabindex="0"><span>Index Card Route Swap</span></div> */
.uiwiki-index-card-route-swap {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-index-card-route-swap > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #c5bff0;
  animation: index_card_route_swap 1.8s ease-in-out infinite alternate;
}
.uiwiki-index-card-route-swap:hover,
.uiwiki-index-card-route-swap:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes index_card_route_swap {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-index-card-route-swap, .uiwiki-index-card-route-swap > span { animation: none; transition: none; }
}
